#!/usr/bin/env python3
"""Minimal clitest runner for antidote markdown tests."""
import os
import re
import subprocess
import sys


def parse_markdown(path):
    """Yield (command, expected_lines, directive) for each zsh block."""
    with open(path, 'r') as f:
        lines = f.read().splitlines()

    blocks = []
    in_block = False
    block_lines = []
    for line in lines:
        if line.strip().startswith('```zsh'):
            in_block = True
            block_lines = []
            continue
        if line.strip() == '```':
            if in_block:
                blocks.append(block_lines)
            in_block = False
            continue
        if in_block:
            block_lines.append(line)

    tests = []
    for block in blocks:
        cmd = None
        expected = []
        directive = None
        for line in block:
            if line.startswith('%'):
                if cmd is not None:
                    tests.append((cmd, expected, directive))
                rest = line[1:]
                if rest.startswith(' '):
                    rest = rest[1:]
                # directive
                if '#=>' in rest:
                    idx = rest.index('#=>')
                    directive = rest[idx + 3:].strip()
                    rest = rest[:idx].rstrip()
                else:
                    directive = None
                cmd = rest
                expected = []
            else:
                expected.append(line)
        if cmd is not None:
            tests.append((cmd, expected, directive))
    return tests


def main():
    if len(sys.argv) != 2:
        print("Usage: run_clitest.py <markdown-file>", file=sys.stderr)
        sys.exit(1)

    testfile = sys.argv[1]
    testdir = os.path.dirname(os.path.abspath(testfile))
    project = os.path.dirname(testdir)
    os.chdir(project)

    tests = parse_markdown(testfile)

    proc = subprocess.Popen(
        ['zsh', '-f'],
        stdin=subprocess.PIPE,
        stdout=subprocess.PIPE,
        stderr=subprocess.STDOUT,
        text=True,
        cwd=project,
    )

    total = passes = failures = 0
    marker = '__CLITEST_END__'
    status_var = '__CLITEST_STATUS__'

    for cmd, expected, directive in tests:
        total += 1
        if cmd:
            # Send the command and a status marker line.
            send = f"{cmd}\n{status_var}=$?; print -r -- \"{marker}:${{{status_var}}}\"\n"
        else:
            send = f"{status_var}=0; print -r -- \"{marker}:${{{status_var}}}\"\n"
        proc.stdin.write(send)
        proc.stdin.flush()

        # Read until the marker line.
        output_lines = []
        status = None
        while True:
            line = proc.stdout.readline()
            if not line:
                break
            line = line.rstrip('\n')
            if line.startswith(f'{marker}:'):
                try:
                    status = int(line.split(':', 1)[1])
                except ValueError:
                    status = None
                break
            output_lines.append(line)

        ok = True
        diff = ''
        if directive:
            if directive.startswith('--exit'):
                try:
                    expect_exit = int(directive.split(' ', 1)[1])
                except Exception:
                    expect_exit = 0
                if status != expect_exit:
                    ok = False
                    diff = f'exit: expected {expect_exit}, got {status}'
            elif directive.startswith('--file'):
                fpath = directive.split(' ', 1)[1]
                if not os.path.isabs(fpath):
                    fpath = os.path.join(testdir, fpath)
                if not os.path.exists(fpath):
                    ok = False
                    diff = f'file not found: {fpath}'
                else:
                    with open(fpath, 'r') as f:
                        expected = f.read().splitlines()
                    if output_lines != expected:
                        ok = False
                        diff = f'output differs from file {fpath}'
        else:
            if status != 0:
                ok = False
                diff = f'exit: expected 0, got {status}'
            elif output_lines != expected:
                ok = False
                diff = 'output differs'

        if not ok:
            failures += 1
            print(f'FAIL [{total}]: {cmd}', file=sys.stderr)
            print(diff, file=sys.stderr)
            print('--- output ---', file=sys.stderr)
            for l in output_lines:
                print(l, file=sys.stderr)
            print('--- expected ---', file=sys.stderr)
            for l in expected:
                print(l, file=sys.stderr)
            print('---', file=sys.stderr)
        else:
            passes += 1

    proc.stdin.close()
    proc.wait()
    print(f'tests: {total}, passed: {passes}, failed: {failures}')
    sys.exit(1 if failures else 0)


if __name__ == '__main__':
    main()

